def get_cpu_value(v):
    if type(v) == torch.Tensor and v.is_cuda:
        return v.cpu()
    return v
def get_gpu_value(v):
    if type(v) == torch.Tensor and not v.is_cuda:
        return v.cuda()
    return v

def change_to_same_f64(a, b):
    if a.dtype != torch.float64:
        a = a.double()
    if b.dtype != torch.float64:
        b = b.double()
    return a, b
def change_to_f64(v):
    if v.dtype != torch.float64:
        v = v.double()
    return v

