def h_lerp_n_n_n(a, b, h):
    return (1 - h) * a + h * b
def h_lerp_v_v_n(a, b, h):
    a = get_gpu_value(a)
    b = get_gpu_value(b)
    h = get_gpu_value(h)
    return (1 - h) * a + h * b
def h_lerp_v_v_v(a, b, h):
    a = get_gpu_value(a)
    b = get_gpu_value(b)
    h = get_gpu_value(h)
    return (1 - h) * a + h * b
def h_lerp_v_v_t_n(a, b, h):
    a = get_gpu_value(a)
    b = get_gpu_value(b)
    h = get_gpu_value(h)
    a = torch.broadcast_to(a, (len(h), len(a)))
    b = torch.broadcast_to(b, (len(h), len(b)))
    return ((1 - h) * a.T + h * b.T).T
def h_lerp_v_t_v_t_n(a, b, h):
    a = get_gpu_value(a)
    b = get_gpu_value(b)    
    h = get_gpu_value(h)
    a = torch.broadcast_to(a, (len(b), len(a)))
    return ((1 - h) * a.T + h * b.T).T
