def h_smoothstep_n_n_n(a, b, v):
    a = get_s_gpu_tensor(a)
    b = get_s_gpu_tensor(b)
    v = get_s_gpu_tensor(v)
    t = (v - a) / (b - a)
    t = torch.clip(t, gpu_zero_tensor, gpu_one_tensor)
    return t * t * (3 - 2 * t)
