def h_reflect_v_v(v1, v2):
    v1 = get_gpu_value(v1)
    v2 = get_gpu_value(v2)
    v1, v2 = change_to_same_f64(v1, v2)
    dot = torch.dot(v1, v2)
    return v1 - 2 * dot * v2
def h_reflect_t_v_v(v1, v2):
    v1 = get_gpu_value(v1)
    v2 = get_gpu_value(v2)
    v1, v2 = change_to_same_f64(v1, v2)
    dot = torch.linalg.vecdot(v1, v2)
    dot = dot.reshape(len(dot), 1)
    _2_dot_v2 = torch.mul(dot, v2) * 2.0
    return v1 - _2_dot_v2
